import {Event, EventContainer} from 'jibo-typed-events';
import {State, StateMachine, Transition} from 'jibo-state-machine';

import {CircadianGoalProvider} from '../CircadianGoalProvider';
import {ChooseTimeState} from './ChooseTimeState';
import {SleepState} from '../../../common/Types';
import {SkillUtils} from '../../../common/Utils';
import {InterruptState} from './InterruptState';
import {log} from '../log';


export { } // For Type definition purposes


/**
 * @class SMEvents
 * @internal
 * @private
 * @extends {EventContainer}
 */
export class SMEvents extends EventContainer {
    earlyNightTimeStarts = new Event<any>(`Early night time starts`);
    nightTimeStarts = new Event<any>(`Night time starts`);
    dayTimeStarts = new Event<any>(`Day time starts`);
    goToSleep = new Event<any>(`"Go to sleep"`);
    hjInterruption = new Event<any>(`HJ Interruption`);
}

/**
 * @class CircadianStateMachine
 * @internal
 * @private
 * @extends {StateMachine}
 */
export class CircadianStateMachine extends StateMachine {

    events = new SMEvents();

    chooseTodState = new ChooseTimeState(this);
    asleepState = new State(this, SleepState.ASLEEP);
    fallingAsleepState = new State(this, SleepState.FALLING_ASLEEP);
    awakeState = new State(this, SleepState.AWAKE);

    interruptSleepState = new InterruptState(this);

    lastHJInterruptionTimer: any;

    onHjHeard = () => this.events.hjInterruption.emit();

    constructor(public parent: CircadianGoalProvider) {
        super();
    }

    init() {
        const jibo = this.parent.parent.jibo;

        this.setInitial(this.chooseTodState);

        // Add logging on entry into states
        this.awakeState.onEntry = () => log.info(`Circadian: entering '${this.awakeState.name}'`);
        this.fallingAsleepState.onEntry = () => log.info(`Circadian: entering '${this.fallingAsleepState.name}'`);
        this.asleepState.onEntry = () => log.info(`Circadian: entering '${this.asleepState.name}'`);

        // Add transitions
        this.chooseTodState.installTransitions(this.awakeState, this.fallingAsleepState, this.asleepState);

        // Transitions that apply to all sleep states
        [   this.awakeState,
            this.fallingAsleepState,
            this.asleepState,
            this.interruptSleepState].forEach(s => {
                s.addTypedEventTransition(this.events.goToSleep, this.asleepState);
        });

        // Asleep state outbound transitions
        this.awakeState.addTypedEventTransition(this.events.earlyNightTimeStarts, this.fallingAsleepState);
        this.awakeState.addTypedEventTransition(this.events.nightTimeStarts, this.asleepState);

        // Falling asleep state outbound transitions
        this.fallingAsleepState.addTypedEventTransition(this.events.dayTimeStarts, this.awakeState);
        this.fallingAsleepState.addTypedEventTransition(this.events.nightTimeStarts, this.asleepState);
        this.fallingAsleepState.addTypedEventTransition(this.events.hjInterruption, this.interruptSleepState);

        // Falling asleep state outbound transitions
        this.asleepState.addTypedEventTransition(this.events.dayTimeStarts, this.awakeState);
        this.asleepState.addTypedEventTransition(this.events.hjInterruption, this.interruptSleepState);

        // Interrupt state outbound transitions
        this.interruptSleepState.installTransitions(this.chooseTodState);

        // On every state transition we consider emitting a sleep change event        
        this.stateChanged.on((transition: Transition) => {
            this.parent.checkSleepStateChange();
        });

        jibo.gl.events.hjHeard.on(this.onHjHeard);
    }

    dispose() {
        const jibo = this.parent.parent.jibo;
        jibo.gl.events.hjHeard.removeListener(this.onHjHeard);
        this.destroy();
    }
}
