import {AnimationAction} from './AnimationAction';
import {ActionRuntime} from '../../common/ActionRuntime';
import {DriveName, ActionResult, SleepState} from '../../common/Types';
import {State} from '../../common/State';
import {SkillNames} from '../../common/Utils';
import {TimeUtils} from 'jibo-cai-utils';


export { }

/**
 * The class of idle animations available when Jibo has been in Idle for a shorter period of time.
 *
 * @export
 * @class jibo.action.action.IdleAnimation5min
 * @internal
 * @private
 * @extends {AnimationAction}
 */
export class IdleAnimationVisual extends AnimationAction {
    constructor (public parent: ActionRuntime) {
        super(parent, {
                category: 'idle',
                includeSomeMeta: ['pong', 'paddleball', 'art'],
                randomOrientation: true
            },
            {
                driveEffects: new Map<DriveName, number>([<[DriveName, number]>[DriveName.PLAYFUL, -1.0]])
            },
            `IdleAnimationVisual`);
    }

    /**
     * Determines if this action is eligible in a given state
     * Should be overridden by subclasses
     * @param {object} state
     * @return {boolean}
     */
    isEligible(state: State): boolean {
        return (state.skillName===SkillNames.IDLE) &&
            (state.sleep === SleepState.AWAKE) &&
            (this.parent.dateProvider.getDate().getTime() - state.skillStartTime.getTime()) > TimeUtils.minutesToMs(5);  // is the Idle requirement redundant?
    }

    protected async runInternal(): Promise<ActionResult> {
        const retVal = await super.runInternal();
        if (retVal) {
            this.parent.jibo.analytics.track('Idle behavior', {idle_behavior_class: `visual`});
        }
        return retVal;
    }
}


