import {Action} from '../Action';
import {ActionRuntime} from '../../common/ActionRuntime';
import {ActionResult} from '../../common/Types';
import {HeadTouchData} from "../../goal/goals/HeadTouchGoal";

/**
 * @private
 */
export class EmitHeadPat extends Action {

    constructor(parent: ActionRuntime, private data: HeadTouchData) {
        super(parent, `Emit Head Pat Action`);
    }

    protected async runInternal(): Promise<ActionResult> {
        this.parent.events.headPat.emit(this.data);
        return ActionResult.SUCCEEDED;
    }
}

export {} // Needed for type definitions