import {Goal} from './Goal';
import {State} from '../common/State';
import {GoalPriorityType, GoalFinishedStatus} from '../common/Types';
import {ActionRuntime} from '../common/ActionRuntime';
import {GoalParallelism} from './GoalParallelism';
import {BeSSWGoal} from './goals/BeSSWGoal';
import {SSWGoal} from './goals/SSWGoal';
import {HeadTouchGoal} from "./goals/HeadTouchGoal";
import {HJOnlyGoal} from "./goals/HJOnlyGoal";
import {log as parentLog} from './log';

const log = parentLog.createChild('GoalSet');

export {} // For Type definition purposes

/**
 * @private
 */
export class GoalSet {

    public goalParallelism = new GoalParallelism();
    
    private goals: Goal[] = [];

    constructor(public parent: ActionRuntime) {
        // We register all the types of goals which can be achieved in parallel
        this.goalParallelism.registerParallelGoalConstructors(BeSSWGoal, SSWGoal, (beGoal: BeSSWGoal, sswGoal: SSWGoal) => {
            return (beGoal.data.skillName === sswGoal.data.skillName); 
        });
        this.goalParallelism.registerParallelGoalConstructors(BeSSWGoal, HeadTouchGoal);
        this.goalParallelism.registerParallelGoalConstructors(HeadTouchGoal, SSWGoal);
        this.goalParallelism.registerParallelGoalConstructors(BeSSWGoal, HJOnlyGoal);
    }

    /**
     * Add a goal to the goal list
     * @param {Goal} goal
     */
    addGoal(goal: Goal): void {
        log.debug('Adding goal: ', goal.name, ', nr of existing goals: ', this.goals.length);
        let toRemove: Goal[] = [];
        let shouldAdd = true;

        // Function to consider removing existing goal
        const considerRemovingGoal = (oldGoal: Goal) => {
            // Now we need to consider if the existing goal is currently being acted on
            const active = this.parent.activeGoals.find(current => current.goal === oldGoal);
            if (active) {
                active.action.cancel();
            }
            toRemove.push(oldGoal);
        };

        // If we have a singleton goal
        if (goal.options.priorityType !== GoalPriorityType.REGULAR) {
            log.debug('Singleton goal');

            for (let i=0; i<this.goals.length; i++) {
                const otherGoal = this.goals[i];
                // If the goals are of the exact same class
                if (otherGoal.constructor === goal.constructor) {
                    log.debug('Found goal of same type');

                    if (goal.options.priority > otherGoal.options.priority) {
                        // If incoming goal is of highest priority
                        log.debug('Incoming is higher priority');
                        considerRemovingGoal(otherGoal);
                    } else if (otherGoal.options.priority > goal.options.priority) {
                        // We should not add this new goal since it is of lower priority
                        log.debug('Incoming is lower priority');
                        shouldAdd = false;
                    } else if (goal.options.priorityType === GoalPriorityType.SINGLETON_KEEP_FIRST) {
                        // Our mode is to keep the first goal
                        log.debug('Priority type is SINGLETON_KEEP_FIRST');
                        shouldAdd = false;
                    } else if (goal.options.priorityType === GoalPriorityType.SINGLETON_KEEP_LAST) {
                        log.debug('Priority type is SINGLETON_KEEP_LAST');
                        // Our mode is to keep the last incoming goal
                        considerRemovingGoal(otherGoal);
                    }
                }
            }
        }

        // Remove goals
        toRemove.forEach(g => {
            this.removeGoal(g);
            g.setFinishedStatus(GoalFinishedStatus.CANCELED);
        });

        if (shouldAdd) {
            this.goals.push(goal);
            this.parent.events.goalAdded.emit(goal);
        } else {
            goal.setFinishedStatus(GoalFinishedStatus.CANCELED);
        }
    }

    /**
     * Chooses best goal to achieve and removes it from list
     * TODO: Improve this selection
     */
    chooseGoal(state: State): Goal {
        if (this.goals.length === 0) {
            return null;
        }

        const eligibleGoals: Goal[] = [];
        const nextGoals: Goal[] = [];
        const canBeCulled: Goal[] = [];
        this.goals.forEach(goal => {
            if (goal.canBeCulled(state)) {
                canBeCulled.push(goal);
            } else {
                nextGoals.push(goal);
                if (goal.isEligible(state)) {
                    eligibleGoals.push(goal);
                }
            }
        });

        this.goals = nextGoals;

        // Cull all out-of-date goals
        canBeCulled.forEach(g => g.setFinishedStatus(GoalFinishedStatus.CULLED));

        // Pick highest priority goal from eligible goals
        if (eligibleGoals.length) {
            // Sort in descending order
            eligibleGoals.sort((a: Goal, b: Goal) => {
                const diff = b.options.priority - a.options.priority;
                if (diff === 0) {
                    // Break ties randomly
                    return (Math.random() > 0.5) ? -1 : 1;
                } else {
                    return diff;
                }
            });
            return eligibleGoals[0];
        }
        else {
            return null;
        }
    }

    /**
     * Removes goal from lists
     * @param goal
     */
    removeGoal(goal: Goal) {
        let index = this.goals.indexOf(goal);
        if (index > -1) {
            this.goals.splice(index, 1);
        }
        else {
            log.warn(`Trying to remove goal '${goal.name}' but didn't find it in goal list`);
        }
    }
}
