/**
 * Get drive value.
 * @method jibo.action#getMotivationalDriveValue
 * @param drive {jibo.action.types#DriveName} Name of the drive to get a value for.
 * @returns {number} drive value
 * @intdocs
 */
export function getMotivationalDriveValue(drive: types.DriveName): number {
    return _runtime.motivations.drives.get(drive).value;
}

// For now the effect is unconstrained. Before finalizing the API, we should consider whether it
// would be better to give skills less power--a discrete bump in one direction or the other.
/**
 * Apply motivational effect (i.e., increment/decrement drive value)
 * @intdocs
 * @export
 * @method jibo.action#applyMotivationalEffect
 * @param drive {jibo.action.types#DriveName} Name of the drive to apply the effect to.
 * @param effect {number} from -1.0 (fully satiate drive) to 1.0 (fully saturate drive).
 */
export function applyMotivationalEffect(drive: types.DriveName, effect: number): void {
    _runtime.motivations.drives.get(drive).applyEffect(effect);
}

/**
 * Configure the action runtime.
 * @method jibo.action#configure
 * @param configOptions {jibo.action.types#ActionSystemConfiguration} Dictionary of configuration options.
 */
export function configure(configOptions: types.ActionSystemConfiguration): void {
    _runtime.configure(configOptions);
}
