import {Action} from '../Action';
import {ActionRuntime} from '../../common/ActionRuntime';
import {ActionResult, ActionOptions, AnimationGoalData} from '../../common/Types';
import * as _ from 'lodash/lodash.min';


// Only importing type definition
import JiboImport = require('../../../../jibo'); // NOTE: only for type declaration, not runtime dependency
type Animation = JiboImport.animDB.Animation;
type Playback = JiboImport.animDB.Playback;
type AnimConfig = JiboImport.animDB.AnimConfig;

/**
 * @private
 */
export class AnimationAction extends Action {

    protected instance: Playback;

    constructor(parent: ActionRuntime, private data: AnimationGoalData, options?: ActionOptions, name=`Animation Action`) {
        super(parent, name, options);
    }

    protected async runInternal(): Promise<ActionResult> {
        let anim: Animation;
        if (this.data.category) {
            const animRes = this.parent.jibo.animDB.query({
                category: this.data.category,
                includeMeta: this.data.includeMeta || [],
                includeSomeMeta: this.data.includeSomeMeta || [],
                excludeMeta: this.data.excludeMeta || []
            });
            if (!animRes || animRes.matching.length === 0) {
                this.log.error(`Couldn't find animation of category '${this.data.category}'`);
                return ActionResult.FAILED;
            }
            anim = _.sample(animRes.matching);
        } else if (this.data.name) {
            anim = this.parent.jibo.animDB.getAnimByName(this.data.name);
            if (!anim) {
                this.log.error(`No animation of name '${this.data.name}' found`);
                return ActionResult.FAILED;
            }
        } else {
            this.log.error(`Invalid anim data`);
            return ActionResult.FAILED;
        }

        const animConfig: AnimConfig = {};
        const Orientation = this.parent.jibo.animDB.Orientation;
        if (this.data.randomOrientation) {
            animConfig.orientation = (Math.random() > 0.5) ? Orientation.LEFT : Orientation.RIGHT;
        }
        this.log.info(`AnimationAction playing animation of name: '${anim.name}', sampled from cat: '${this.data.category}', meta: '${this.data.includeMeta}'`);
        this.instance = await anim.createFromConfig(animConfig);
        await this.instance.play();

        this.instance = null;
        return ActionResult.SUCCEEDED;
    }

    protected async cancelInternal(): Promise<any> {
        if (this.instance) {
            this.instance.stop();
        }
    }
}

export {} // Needed for type definitions
