import {ActionRuntime} from '../../common/ActionRuntime';
import {GoalProvider} from '../GoalProvider';
import {SkillNames} from '../../common/Utils';
import {SSWGoal} from '../goals/SSWGoal';


export {} // For Type definition purposes

/**
 * @private
 */
export class HJNoMatchGoalProvider extends GoalProvider {

    private handleHJNoMatchBind = this.handleHJNoMatch.bind(this);

    constructor(parent: ActionRuntime) {
        super(parent, 'HJNoMatch goal provider');
    }

    init() {
        this.parent.jibo.gl.events.noMatch.on(this.handleHJNoMatchBind);
    }

    dispose() {
        this.parent.jibo.gl.events.noMatch.removeListener(this.handleHJNoMatchBind);
    }

    handleHJNoMatch(data: any) {
        if(!data.result.triggeredByHJ) {
            return;
        }
        // Only generate HJNoMatch goals when in Idle
        if (this.parent.currentSkillName === SkillNames.IDLE) {
            this.provideGoal(new SSWGoal(this.parent, {
                skillName: SkillNames.IDLE,
                skillOptions: {
                    intent: 'hjNomatch',
                    text: data.result.Input
                },
                criteria: {
                    currentSkill: SkillNames.IDLE
                }
            }, `HJNoMatch`));
        }
    }
}
