import {Goal} from '../Goal';
import {ActionRuntime} from '../../common/ActionRuntime';
import {State, SkillNames} from "../../common";
import {GoalPriority} from '../GoalPriority';
import {GoalPriorityType} from '../../common/Types';


export {} // For Type definition purposes

/**
 * @internal
 * @private
 */
export class MotivationGoal extends Goal {

    constructor(parent: ActionRuntime) {
        super(parent, 'MotivationGoal', {
            priority: GoalPriority.Motivation,
            priorityType: GoalPriorityType.SINGLETON_KEEP_FIRST,
            maxAttempts: 1,
        });
    }


    /**
     * Whether this goal is eligible given the state
     * @param {State} state
     * @return {boolean}
     */
    isEligible(state: State): boolean {
        // Only allow this goal when in skill Idle
        if (state.skillName !== SkillNames.IDLE) {
            return false;
        }
        // need to check drive/threshold status of all motivation drives
        return this.parent.motivations.drivesAboveThreshold().length > 0;
    }

    /**
     * Whether this goal can be removed from a goal set since
     * its context will never be achieved
     * @param {State} state
     */
    canBeCulled(state: State): boolean {
        // if all drives have been addressed
        return !(this.parent.motivations.drivesAboveThreshold().length > 0);
    }
}
