import { State, Transition } from 'jibo-state-machine';

import { TimeOfDay } from '../../../common/Types';
import { CircadianStateMachine } from './CircadianStateMachine';


export { } // For Type definition purposes

/**
 * @class ChooseTimeState
 * @extends {State}
 * @internal
 * @private
 */
export class ChooseTimeState extends State {

    private awakeState: State;
    private fallingAsleepState: State;
    private asleepState: State;

    constructor(private parent: CircadianStateMachine) {
        super(parent, `Time of day?`);

        this.onEntry = (transition: Transition) => {
            // We transition to falling asleep state upon entry if it is night
            const tod = this.parent.parent.currentToD;
            if (tod === TimeOfDay.NIGHT_EARLY) {
                this.transitionTo(this.fallingAsleepState);
            } if (tod === TimeOfDay.NIGHT) {
                this.transitionTo(this.asleepState);
            } else {
                this.transitionTo(this.awakeState);
            }
        };
    }

    public installTransitions(awakeState: State, fallingAsleepState: State, asleepState: State) {
        this.awakeState = awakeState;
        this.fallingAsleepState = fallingAsleepState;
        this.asleepState = asleepState;
        this.addInternalTransition(`Daytime`, awakeState);
        this.addInternalTransition(`Early Nighttime`, fallingAsleepState);
        this.addInternalTransition(`Nighttime`, asleepState);
    }
}
