import {ActionRuntime} from '../../common/ActionRuntime';
import {GoalProvider} from '../GoalProvider';
import {HeadTouchGoal, HeadTouchData} from '../goals/HeadTouchGoal';


export {} // For Type definition purposes

/**
 * @private
 */
export class HeadTouchGoalProvider extends GoalProvider {

    private touchBind = this.handleHeadTouch.bind(this);

    constructor(parent: ActionRuntime) {
        super(parent, 'Head Touch Goal Provider');
    }

    init() {
        this.parent.jibo.globalEvents.touchStop.on(this.touchBind);
    }

    dispose() {
        this.parent.jibo.globalEvents.touchStop.removeListener(this.touchBind);
    }

    handleHeadTouch(data: HeadTouchData) {
        const goal = new HeadTouchGoal(this.parent, data);
        this.provideGoal(goal);
    }
}
