import {ActionRuntime} from './ActionRuntime';
import {DateProvider} from './DateProvider';
import {DriveName} from './Types';
import {FindPersonGoal} from '../goal/goals/FindPersonGoal';
import {ProactiveGreetingGoalProvider} from '../goal/goalproviders/ProactiveGreetingGoalProvider';
import { log as parentLog } from './log';

const log = parentLog.createChild('Tunable'); 

let tunable = null;
try {
    tunable = require('jibo-tunable');
} catch(e) {
    // No tunable library found, disabling debug
}

class FakeDateProvider implements DateProvider {
    constructor(private hour: number, private minute) { }

    getDate(): Date {
        const d = new Date();
        d.setHours(this.hour);
        d.setMinutes(this.minute);
        d.setSeconds(0);
        d.setMilliseconds(0);
        return d;
    }
}

const WIN = 'Action System';

export class TunableDebug {

    static setup(runtime: ActionRuntime) {
        if (tunable) {
            const T = tunable.Tunable;

            T.getButtonField(`Log status report`, WIN).events.change.on(() => {
                const state = runtime.createState();
                log.info(`Action System status:`);
                log.info(`State: \n${JSON.stringify(state, null, 4)}`);
                log.info(`Active goals/actions (${runtime.activeGoals.length})`);
                runtime.activeGoals.forEach(g => {
                    log.info(` - goal: '${g.goal.name}', action: '${g.action.name}'`);
                });
            });

            T.getButtonField(`Force pro-active greeting`, WIN).events.change.on(() => {
                runtime.goalProviders.forEach(gp => {
                    if (gp instanceof ProactiveGreetingGoalProvider) {
                        gp.handleVisibleFaceInternal();
                    }
                });
            });
            
            // Here we create an option to fake the time
            const originalDateProvider = runtime.dateProvider;
            T.getDropdownField('Fake time', ['disabled', '5:30 am', '7:00 am', '2:00 pm', '10:00 pm', '10:10 pm', '11:00 pm'], 0, WIN).events.change.on(data => {
                if (data === 'disabled') {
                    runtime.dateProvider = originalDateProvider;
                } else {
                    const [time, am_pm] = data.split(' ');
                    const [hour, minute] = time.split(':');
                    runtime.dateProvider = new FakeDateProvider(
                        (am_pm === 'pm') ? Number(hour) + 12 : Number(hour),
                        Number(minute));
                }
                runtime.circadianGoalProvider.update();
            });

            T.getButtonField(`FallingAsleep: fake long time`, WIN).events.change.on(() => {
                (<any> runtime.circadianGoalProvider.circadianSM.fallingAsleepState).startTime = -1;
            });

            T.getButtonField(`Clear current goal / action`, WIN).events.change.on(() => {
                if (!runtime.activeGoals.length) {
                    log.warn(`No current goal/action to clear`);
                } else {
                    const name = runtime.activeGoals.map(a => a.action.name).join(', ');
                    log.warn(`Canceling current action: ${name}`);
                    runtime.activeGoals.forEach(a => a.action.cancel());
                }
            });

            T.getButtonField(`Create search goal`, WIN).events.change.on(() => {
                runtime.goals.addGoal(new FindPersonGoal(runtime));
            });

            const driveDropdown = T.getDropdownField('Motivational drive', Object.keys(DriveName), 0, WIN);
            T.getButtonField(`Saturate drive`, WIN).events.change.on(() => {
                const drive = runtime.motivations.drives.get(driveDropdown.current);
                (drive as any)._value = drive.threshold;
            });
        }
    }
}
