import { State } from 'jibo-state-machine';
import { CircadianStateMachine } from './CircadianStateMachine';


export { } // For Type definition purposes


const INTERRUPTION_TIMEOUT_MIN = 5;

export class InterruptState extends State {

    doneState: State;

    constructor(parent: CircadianStateMachine) {
        super(parent, `Interrupt`);
        const jibo = parent.parent.parent.jibo;

        let timeOfLastInterruption = -1;

        const interrupt = () => {
            timeOfLastInterruption = Date.now();
        };

        this.onEntry = async () => {
            timeOfLastInterruption = Date.now();
            jibo.gl.events.hjHeard.on(interrupt);
            jibo.system.events.touchOn.on(interrupt);
        };

        this.onExit = () => {
            jibo.gl.events.hjHeard.removeListener(interrupt);
            jibo.system.events.touchOn.removeListener(interrupt);
        };

        this.onUpdate = () => {
            const timeSinceInterrupt = Date.now() - timeOfLastInterruption;
            if (timeSinceInterrupt > INTERRUPTION_TIMEOUT_MIN * 60 * 1000) {
                timeOfLastInterruption = Date.now();
                this.transitionTo(this.doneState);
            }
        };
    }

    installTransitions(doneState: State) {
        this.doneState = doneState;
        this.addInternalTransition('Done', doneState);
    }
}