
import { Goal } from './Goal';
import { DoubleMap } from '../common/Utils';

export { } // For Type definition purposes

/**
 * @private
 * @internal
 */
export type GoalPredicate = (goalA: Goal, goalB: Goal) => boolean;

interface GoalParallel {
    constructorA: Function;
    constructorB: Function;
    goalPredicate?: GoalPredicate;
}

/**
 * This class allows registration of several different goal classes which can be achieved
 * in parallel.
 * @internal
 * @private
 * @class GoalParallelism
 * @memberof jibo.action.goal
 */
export class GoalParallelism {

    private allowedNormal = new DoubleMap<Function, Function, GoalParallel>();
    private allowedInverse = new DoubleMap<Function, Function, GoalParallel>();

    /**
     * Determines whether the two goals can be achieved in parallel
     * @param {Goal} goalA
     * @param {Goal} goalB
     * @returns {boolean}
     * @memberOf GoalParallelism
     */
    canBeAchievedInParallel(goalA: Goal, goalB: Goal): boolean {
        // We first attempt the original order
        let parallel = this.allowedNormal.get(goalA.constructor, goalB.constructor);
        if (parallel) {
            if (parallel.goalPredicate) {
                return parallel.goalPredicate(goalA, goalB);
            } else {
                return true;
            }
        }

        // Now we try the other order
        parallel = this.allowedInverse.get(goalB.constructor, goalA.constructor);
        if (parallel) {
            if (parallel.goalPredicate) {
                // And we apply the predicate with inverted arguments
                return parallel.goalPredicate(goalB, goalA);
            } else {
                return true;
            }
        }

        return false;
    }

    /**
     * Registers two goal constructors that can be acted on in parallel
     * @param {Function} goalConstructorA - The constructor function of the first class of goal
     * @param {Function} goalConstructorB - The constructor function of the second class of goal
     * @param {GoalPredicate} [predicate] - Optional comparison function to be applied to goal
     * pairs of these constructor types. This can be used to further inspect goals for whether
     * they can be performed in parallel
     */
    public registerParallelGoalConstructors(goalConstructorA: Function, goalConstructorB: Function, predicate?: GoalPredicate): void {
        const goalParallel: GoalParallel = {
            constructorA: goalConstructorA,
            constructorB: goalConstructorB,
            goalPredicate: predicate
        };

        this.allowedNormal.set(goalConstructorA, goalConstructorB, goalParallel); 
        this.allowedInverse.set(goalConstructorA, goalConstructorB, goalParallel); 
    }
}
