import {MotivationGoal} from '../goal/goals/MotivationGoal';
import {GoalProvider} from '../goal/GoalProvider';
import {Drive} from './Drive';
import {ActionRuntime} from '../common/ActionRuntime';
import {Action} from '../action/Action';
import {DriveName} from '../common/Types';
import {WakingDrive} from './drives/WakingDrive';
import JiboLog = require("jibo-log");
import { log as rootLog } from '../common/log';


export {} // For Type definition purposes


/**
 * @private
 */
export class MotivationGoalProvider extends GoalProvider {

    constructor(parent: ActionRuntime) {
        super(parent, `Motivation`);
    }

    init() {
        // noop
    }

    dispose() {
        // noop
    }
}

/**
 * @private
 */
export class MotivationSystem {

    public drives = new Map<DriveName, Drive>();

    public goalProvider: MotivationGoalProvider;

    public log:JiboLog;

    constructor(private parent: ActionRuntime) {
        this.drives.set(DriveName.SOCIAL, new WakingDrive(this.parent, DriveName.SOCIAL, 1/120));
        this.drives.set(DriveName.PLAYFUL, new WakingDrive(this.parent, DriveName.PLAYFUL, 1/15));
        this.drives.set(DriveName.HELPFUL, new Drive(DriveName.HELPFUL));

        this.goalProvider = new MotivationGoalProvider(parent);

        this.log = rootLog.createChild('Motivation');
    }

    /**
     * Update all motivational drives and create a goal if needed
     */
    public update() {
        let makeGoal = false;
        this.drives.forEach((drive) => {
            drive.update();
            
            // This is very helpful during dev, but should not be checked-in uncommented.
            // maybe replace this with a Tunable interface?
            //this.log.debug(`${drive.name} value: ${drive.value}`);

            if (drive.value >= drive.threshold) {
                makeGoal = true;
            }
        });
        if (makeGoal) {
            this.goalProvider.provideGoal(new MotivationGoal(this.parent));
        }
    }

    /**
     * Apply the motivational effects of an action to the drives of the motivation system.
     * (Typically called with the action that has just successfully completed)
     * @param {Action} action
     */
    public applyMotivationalEffects(action: Action){
        action.options.driveEffects.forEach((dv, dn) => {
            this.parent.motivations.drives.get(dn).applyEffect(dv);
        });
    }

    /**
     * @returns {Drive[]} array of Drives whose value is at or above their threshold.
     * (For the common use case of checking whether there are any such drives, just
     * check result.length > 0.)
     */
    public drivesAboveThreshold(): Drive[] {
        let aboveThreshold = new Array<Drive>();
        this.drives.forEach((d) => {
            if (d.value >= d.threshold) {
                aboveThreshold.push(d);
            }
        });
        return aboveThreshold;
    }

}
