import {HJData} from './Types';
import {ActionRuntime} from './ActionRuntime';


export namespace data {
}

export interface MemoryRecord<T> {
    time: Date;
    data: T;
}

export type MemoryKey = 'HJData';

export class Memory {

    private map = new Map<MemoryKey, MemoryRecord<any>>();

    constructor(private parent: ActionRuntime) {
        // noop
    }

    /**
     * Returns the memory entry for HJData
     * @returns {MemoryRecord<HJData>}
     */
    public getHJData(): MemoryRecord<HJData> {
        return this.get('HJData');
    }

    /**
     * Sets the memory entry for HJData
     * @param {HJData} data
     */
    public setHJData(data: HJData): void {
        this.set('HJData', data);
    }

    private set(key: MemoryKey, data: any): void {
        this.map.set(key, {
            time: this.parent.dateProvider.getDate(),
            data: data 
        });
    }

    private get(key: MemoryKey): MemoryRecord<any> {
        return this.map.get(key);
    }    
}