import {Action} from '../Action';
import {ActionResult, BeSSWGoalData} from '../../common/Types';
import {ActionRuntime} from '../../common/ActionRuntime';

/**
 * @internal
 */
export class BeSkillSwitchAction extends Action {

    /**
     * Constructs an action object
     * @param {ActionRuntime} parent - Behavior runtime parent
     * @param {BeSSWGoalData} goalData - Be Skill switch goal data
     */
    constructor(parent: ActionRuntime, private goalData: BeSSWGoalData) {
        super(parent, 'Be Skill Switch Action');
    }

    /**
     * Runs action and immediately returns with success
     * @return {Promise<ActionResult>}
     */
    protected async runInternal(): Promise<ActionResult> {
        // Set the current skill to be the skill we're switching into
        this.parent.currentSkillName = this.goalData.skillName;
        return ActionResult.SUCCEEDED;
    }
}

export {} // Needed for type definitions