/**
 * Represents what the current time of day is
 * @typedef jibo.action.types#TimeOfDay
 * @property {String} DAY
 * @property {String} NIGHT_EARLY
 * @property {String} NIGHT
 * @property {String} MORNING_EARLY
 * @property {String} MORNING
 */
export type TimeOfDay = 'DAY' | 'NIGHT' | 'NIGHT_EARLY' | 'MORNING_EARLY' | 'MORNING';
export namespace TimeOfDay {
    export const MORNING_EARLY: TimeOfDay = 'MORNING_EARLY';
    export const MORNING: TimeOfDay = 'MORNING';
    export const DAY: TimeOfDay = 'DAY';
    export const NIGHT: TimeOfDay = 'NIGHT';
    export const NIGHT_EARLY: TimeOfDay = 'NIGHT_EARLY';

    /**
     * Returns the time of day for a given hour.
     * @method jibo.action.types#getTimeOfDay
     * @param {Date} time - Time to evaluate
     * @return {jibo.action.types#TimeOfDay}
     */
    export function getTimeOfDay(time: Date): TimeOfDay {
        const hour = time.getHours();
        const min = time.getMinutes();

        // If it is night time
        if (hour < EARLY_MORNING_HOUR || hour >= NIGHT_HOUR) {
            if (hour === NIGHT_HOUR && min <= NIGHT_MINUTE) {
                return TimeOfDay.NIGHT_EARLY;
            } else {
                return TimeOfDay.NIGHT;
            }
        } else if (hour < MID_MORNING_HOUR) {
            return TimeOfDay.MORNING_EARLY;
        } else if (hour < DAY_HOUR) {
            return TimeOfDay.MORNING;
        } else if (hour < NIGHT_HOUR) {
            return TimeOfDay.DAY;
        }
    }
}

