import {ActionRuntime} from '../../common/ActionRuntime';
import {TimeOfDay, SleepState} from '../../common/Types';
import {SkillNames} from '../../common/Utils';
import {GoalProvider} from '../GoalProvider';
import {SSWGoal} from '../goals/SSWGoal';
import {CircadianStateMachine} from './circadian/CircadianStateMachine';


export { } // For Type definition purposes

/**
 * @internal
 * @private
 */
export class CircadianGoalProvider extends GoalProvider {

    public circadianSM = new CircadianStateMachine(this);
    public currentToD: TimeOfDay = null;
    private goToSleepHandlerBind = this.goToSleepHandler.bind(this);
    
    private lastSleepState: SleepState;

    constructor(parent: ActionRuntime) {
        super(parent, 'Circadian rhythm goal provider');
    }

    init() {
        this.parent.jibo.globalEvents.sleep.on(this.goToSleepHandlerBind);
        this.circadianSM.init();
        const now = this.parent.dateProvider.getDate();
        this.currentToD = TimeOfDay.getTimeOfDay(now);
        this.circadianSM.start();
        this.lastSleepState = this.getCurrentSleepState();
    }

    dispose() { 
        this.parent.jibo.globalEvents.sleep.removeListener(this.goToSleepHandlerBind);
        this.circadianSM.destroy();
    }

    checkSleepStateChange() {
        const current = this.getCurrentSleepState();
        if (current !== this.lastSleepState) {
            this.lastSleepState = current;
            this.parent.events.sleepChange.emit(current);
        }
    }

    getCurrentSleepState(): SleepState {
        const current = this.circadianSM.getCurrentState();
        if (current === this.circadianSM.fallingAsleepState) {
            return SleepState.FALLING_ASLEEP;
        } else if (current === this.circadianSM.asleepState) {
            return SleepState.ASLEEP;
        } else {
            return SleepState.AWAKE;
        }
    }

    public goToSleepHandler() {
        // If "gotosleep" while not in Idle, switch to Idle
        const state = this.parent.createState();

        if (state.skillName !== SkillNames.IDLE) {
            this.provideGoal(new SSWGoal(this.parent, {
                skillName: SkillNames.IDLE,
                skillOptions: {}
            }));
        }

        // Let state machine know to go to sleep
        this.circadianSM.events.goToSleep.emit();
    }

    public update() {
        const now = this.parent.dateProvider.getDate();
        const newToD = TimeOfDay.getTimeOfDay(now);
        if (newToD !== this.currentToD) {
            this.currentToD = newToD;
            if (this.currentToD === TimeOfDay.MORNING ||
                this.currentToD === TimeOfDay.DAY) {
                this.circadianSM.events.dayTimeStarts.emit();
            } else if (this.currentToD === TimeOfDay.NIGHT_EARLY) {
                this.circadianSM.events.earlyNightTimeStarts.emit();
            } else if (this.currentToD === TimeOfDay.NIGHT) {
                this.circadianSM.events.nightTimeStarts.emit();
            }
        }
        this.circadianSM.update();
    }
}
