import {Goal} from "../../goal/Goal";
import {Action} from "../Action";
import {ActionPolicy} from "./ActionPolicy";
import {ActionRuntime} from "../../common/ActionRuntime";
import {HJGoal} from "../../goal/goals/HJGoal";
import {FindPersonGoal} from "../../goal/goals/FindPersonGoal";
import {HJOnlyGoal} from "../../goal/goals/HJOnlyGoal";
import {BasicLookat} from "../actions/BasicLookat";
import {SearchAction} from "../actions/SearchAction";
import {HJOrient} from "../actions/HJOrient";
import {SkillNames} from "../../common/Utils";
import {SSWGoal} from "../../goal/goals/SSWGoal";
import {SSWAction} from "../actions/SSWAction";
import {State} from "../../common/State";
import {AnimationAction} from '../actions/AnimationAction';
import {AnimationGoal} from '../../goal/goals/AnimationGoal';
import {HeadTouchGoal} from "../../goal/goals/HeadTouchGoal";
import {HeadTouch} from "../actions/HeadTouch";
import {EmitHeadPat} from "../actions/EmitHeadPat";
import { BeSSWGoal } from '../../goal/goals/BeSSWGoal';
import { BeSkillSwitchAction } from '../../action/actions/BeSkillSwitchAction';



export {} // For type definition purposes

/**
 * @private
 */
export class BasicPolicy implements ActionPolicy {

    constructor(private parent: ActionRuntime) {
    }

    /**
     * Implements this particular action selection policy.
     * @param {Goal} goal
     * @param {State} state
     * @returns {Action|null}
     */
    selectAction(goal: Goal, state: State): Action|null {
        if (goal instanceof HJGoal) {
            const hjGoal = goal as HJGoal;
            const pos = hjGoal.hjData.primary.position;
            if (state.skillName === SkillNames.IDLE) {
                // We use HJOrient if we're in Idle
                return new HJOrient(this.parent, pos);
            } else {
                // Otherwise we use the simpler/quicker BasicLookat
                return new BasicLookat(this.parent, pos);
            }
        } else if (goal instanceof BeSSWGoal) {
            // We simply immediately succeed at this goal
            return new BeSkillSwitchAction(this.parent, (goal as BeSSWGoal).data);
        } else if (goal instanceof HJOnlyGoal) {
            // For HJ Only goals we switch into Greetings (if we're in Idle)
            const data = {
                NLParse: {
                    skill: SkillNames.GREETINGS,
                    intent: 'heyJibo'
                }
            };
            return new SSWAction(this.parent, SkillNames.GREETINGS, data);
        } else if (goal instanceof SSWGoal) {
            // If the goal is a skill switch goal
            const sswGoal = goal as SSWGoal;
            return new SSWAction(this.parent, sswGoal.data.skillName, sswGoal.data.skillOptions);
        } else if (goal instanceof AnimationGoal) {
            // If the goal is an animation goal
            const animGoal = goal as AnimationGoal;
            return new AnimationAction(this.parent, animGoal.data);
        } else if (goal instanceof FindPersonGoal) {
            // If the goal is a find person goal
            // const findGoal = goal as FindPersonGoal;
            return new SearchAction(this.parent);
        } else if (goal instanceof HeadTouchGoal) {
            const headTouchGoal = goal as HeadTouchGoal;
            if (state.skillName === SkillNames.IDLE) {
                return new EmitHeadPat(this.parent, headTouchGoal.data);
            }
            else {
                return new HeadTouch(this.parent);
            }
        }
    }
}
