
export {}

/**
 * @internal
 * @private
 */
export type UpdateFunction = () => void;

/**
 * @internal
 * @private
 */
interface Entry {
    update: UpdateFunction;
    last: number;
    interval: number;
}

/**
 * @internal
 * @private
 */
export class Updater {

    private updateables: Entry[] = [];

    /**
     * Clears the list of updateables
     */    
    public clear() {
        this.updateables = [];
    }

    /**
     * Adds an element to be updated at an interval
     * @param {UpdateFunction} updatable - Update method to call
     * @param {number} [intervalMs=-1] - Update interval in ms
     * @memberOf Updater
     */
    public addUpdateable(update: UpdateFunction, intervalMs = -1) {
        this.updateables.push({
            update,
            interval: intervalMs,
            last: -1
        });
    }

    /**
     * Should be called with some frequency to update elements
     * @memberOf Updater
     */
    public update() {
        const now = Date.now();
        for (let i = 0; i < this.updateables.length; i++) {
            const el = this.updateables[i];
            if (el.interval === -1 || (now - el.last) > el.interval) {
                el.last = now;
                el.update();
            }
        }
    }
}
