import {constrainToBounds} from '../common/Utils';
import {TimeUtils} from 'jibo-cai-utils';

export {} // For type definition purposes


/**
 * @private
 */
export class Drive {

    /**
     * The rate at which the drive increments or decrements.
     * rate per minute, so 1/60=0.0166666666 will go from 0 to 1 in an hour.
     * It is sometimes helpful to think of this as 1/period, where period is the minutes it
     * takes for the drive to go from 0 to 1.
     * @type {number}
     */
    public ratePerMin = 0;

    /**
     * The threshold at which a goal is created to address this drive.
     * @type {number}
     */
    public threshold = 1;

    /**
     * Timestamp (ms since epoch) of the last update. (Needed to tie rate to wall clock time.)
     * @type {any}
     */
    lastUpdate: number;

    protected _value = 0;

    constructor(public name: string, ratePerMin: number = 0) {
        // sanity check rate
        if (ratePerMin < 0) {
            console.error(`invalid rate for drive ${name}: ${ratePerMin}. Setting to 0.`);
            ratePerMin = 0;
        }
        this.ratePerMin = ratePerMin;
    }

    /**
     * The value of the drive. 0.0=fully satiated; 1.0=starved
     * @method jibo.action.Drive#value
     * @returns {number}
     * @intdocs
     */
    get value(): number {
        return this._value;
    }

    
    public update() {
        // update value and threshold based on time and other factors
        this.computeDriveIncrement();
    }

    /**
     * Apply a change to the drive's value.
     *
     * @param {number} effect The increment to the drive's value. The value is constrained
     * to be between 0 and 1.
     * @method jibo.action.Drive#applyEffect
     */
    public applyEffect(effect:number): void {
        this._value = constrainToBounds(this.value + effect, 0, 1);
    }

    /**
     * Compute increment to drive value, based on rate and time since last update
     * @private
     * @memberOf Drive
     */
    private computeDriveIncrement() {
        if (!this.lastUpdate) {
            // this is the first update tick
            // just set lastUpdate and continue
            this.lastUpdate = Date.now();
        } else {
            // get wall clock delta between last tick and this one
            let now = Date.now();
            let delta_t = now - this.lastUpdate; // delta in ms
            // multiply time elapsed by rate to get increment
            let delta_d = TimeUtils.msToMinutes(delta_t) * this.ratePerMin; // I'm a bit worried about underflow
            this._value = constrainToBounds(this._value + delta_d, 0, 1);
            // bounds checking for value
            this.lastUpdate = now;
        }
    }

}



